/*
 * @name GetCountryIdByCompanyLocation
 * @date 22.01.2021
 * @author Isro Syaeful Iman
 * @param ucId		unique company id
 * @param locId		location Id
 * @return infotable ("HPMC.Core.CompanyLocationId.DS")
 *
 * [INPROGRESS] [06/01/2020] 	Get country id by company and location id
 */
var result;
var loggerBeginning = "[" + me.name + ":GetCountryIdByCompanyLocation]";
(function () {
    try {
        ucId = ucId === undefined ? "" : ucId;
        locId = locId === undefined ? "" : locId;

        let company = Things["HPMC.Core.Company.DT"].QueryDataTableEntries({
            query: {
                filters: {
                    type: "EQ",
                    fieldName: "company_id",
                    value: ucId
                }
            } /* QUERY */
        });
        let tempData = DataShapes["HPMC.Core.CompanyLocationId.DS"].CreateValues();
        tempData.ucId = ucId || "";
        tempData.locId = locId || "";
        tempData.countryId = company.country_id || "";
        tempData.machineType = "Sawing";
        result = tempData;
    } catch (error) {
        logger.error(loggerBeginning + " failed to get country id by company and location id - " + error);
    }
})();


/*
 * @name GetUserCompanyLocation
 * @date 13.01.2021
 * @author Isro Syaeful Iman
 * @param userName	username of user
 * @return String
 *
 * [COMPLETED] [06/01/2020] 	Get company and location id of user in string ( format : "ucId.locId")
 */
var result;
var loggerBeginning = "[" + me.name + ":GetUserCompanyLocation]";
(function () {
    if (!userName) {
        result = "Region";
        return;
    }

    try {
        // result: INFOTABLE dataShape: "EntityList"
        let orgTable = Users[userName].GetOrganizationalUnits();
        let orgFiltered = Resources["InfoTableFunctions"].Query({
            t: orgTable /* INFOTABLE */,
            query: {
                filters: {
                    type: "LIKE",
                    fieldName: "name",
                    value: "*" + "HPMC." + "*Region*"
                }
            } /* QUERY */
        });
        if (orgFiltered.length === 0) {
            //if user is a member of company unit
            orgFiltered = Resources["InfoTableFunctions"].Query({
                t: orgTable /* INFOTABLE */,
                query: {
                    filters: {
                        type: "AND",
                        filters: [
                            {
                                type: "LIKE",
                                fieldName: "name",
                                value: "*" + "HPMC." + "*"
                            },
                            {
                                type: "NOTLIKE",
                                fieldName: "name",
                                value: "*" + "Region" + "*"
                            }
                        ]
                    }
                } /* QUERY */
            });
        }
        if (orgFiltered.length > 1) {
            //user is responsible for more than one location so we will set the voestalpine logo
            result = "Voestalpine";
        } else {
            let startIndex = orgFiltered.rows[0].name.indexOf(":") + 1;
            let childOrga = orgFiltered.rows[0].name.substring(startIndex);
            let tempSplit = childOrga.split(".");
            let companyIndex = -1;
            let locationIndex = -1;
            tempSplit.forEach((data, i) => {
                if (data.indexOf("UC") >= 0) {
                    companyIndex = i;
                }
                if (data.indexOf("LOC") >= 0) {
                    locationIndex = i;
                }
            });
            if (companyIndex > 0 && locationIndex > 0) {
                let tempRegion = tempSplit[companyIndex - 2];
                let tempUcId = tempSplit[companyIndex].substring(2);
                let tempLocId = tempSplit[locationIndex].substring(3);
                let tempSubRegion = tempSplit[companyIndex - 1];
                result = tempRegion + "." + tempSubRegion + "." + tempUcId + "." + tempLocId;
            } else if (companyIndex > 0) {
                let tempRegion = tempSplit[companyIndex - 2];
                let tempUcId = tempSplit[companyIndex].substring(2);
                let tempSubRegion = tempSplit[companyIndex - 1];
                result = tempRegion + "." + tempSubRegion + "." + tempUcId;
            } else {
                result = childOrga; // "Region";//"Voestalpine";//
            }
        }
    } catch (error) {
        logger.error(loggerBeginning + " Error at [" + error.lineNumber + "]: cannot get company and location id of user : " + error);
    }
})();


/*
 * @name GetUserCompanyLogo
 * @date 15.01.2021
 * @author Isro Syaeful Iman
 * @param userName	username of user
 * @return infotable (HPMC.Core.CompanyLogo.DS)
 *
 * [COMPLETED] [06/01/2020] 	Get Company logo by organization of user
 */
var result;
var loggerBeginning = "[" + me.name + ":GetUserCompanyLogo]";
(function () {
    "use strict";

    try {
        let table = me.GetConfigurationTable({
            tableName: "CompanyUserLogoConfig" /* STRING */
        });

        try {
            let companyLocationId = me.GetUserCompanyLocation({
                userName: userName
            });
            if (companyLocationId.indexOf("Region") === -1) {
                //for non regional or sub-regional level user
                let tempStr = companyLocationId.substr(companyLocationId.indexOf(".") + 1);
                companyLocationId = tempStr.substr(tempStr.indexOf(".") + 1);
            } else companyLocationId = companyLocationId.split(".")[0];

            let tableFiltered = Resources["InfoTableFunctions"].Query({
                t: table /* INFOTABLE */,
                query: {
                    filters: {
                        type: "LIKE",
                        fieldName: "companyLocationId",
                        value: "*" + companyLocationId + "*"
                    }
                } /* QUERY */
            });
            result = tableFiltered;
        } catch (error) {
            result = Resources["InfoTableFunctions"].Query({
                t: table /* INFOTABLE */,
                query: {
                    filters: {
                        type: "EQ",
                        fieldName: "companyLocationId",
                        value: "Region"
                    }
                } /* QUERY */
            });
            logger.error(loggerBeginning + " Error at [" + error.lineNumber + "]: cannot found username company location or username company logo : " + error);
        }

    } catch (error) {
        logger.error(loggerBeginning + " " + error);
    }
})();


/*
 * @name GetUserCountryId
 * @date 20.01.2021
 * @author Isro Syaeful Iman
 * @param user ame	username of user
 * @return string
 *
 * [COMPLETED] [20/01/2020] 	Get user country id
 */
var result;
var loggerBeginning = "[" + me.name + ":GetUserCountryId]";
(function () {
    logger.info(loggerBeginning + " Get country id of user");
    try {
        var ucLocIdTable = me.GetUserCompanyLocationID({
            username: username /* USERNAME */
        });

        try {
            let company = Things["HPMC.Core.Company.DT"].QueryDataTableEntries({
                query: {
                    filters: {
                        type: "LIKE",
                        fieldName: "company_id",
                        value: ucLocIdTable.ucId !== "Region" ? ucLocIdTable.ucId : "2371"
                    }
                } /* QUERY */
            });
            result = company.country_id;
        } catch (error) {
            result = "";
            log.error(loggerBeginning + " cant found country based on company id - ERROR : " + error);
        }
        logger.info(loggerBeginning + " Service Success");
    } catch (error) {
        logger.error(loggerBeginning + " cannot get countryid of user - ERROR:" + error);
    }
})();


/*
 * @name GetUserDefaultInformation
 * @date 13.01.2021
 * @author Isro Syaeful Iman
 * @param user ame	username of user
 * @return infotable (HPMC.Core.CompanyLocationId.DS)
 *
 * [COMPLETED] [06/01/2020] 	Get Default value of country,company,location and machine type of the user
 */
var result;
var loggerBeginning = "[" + me.name + ":GetUserDefaultInformation]";
(function () {
    try {
        //		result = me.GetUserCompanyLocationID({
        //			username: username /* USERNAME */
        //		});
        // CreateInfoTableFromDataShape(infoTableName:STRING("InfoTable"), dataShapeName:STRING):INFOTABLE(HPMC.Core.CompanyLocationId.DS)
        let tempData = DataShapes["HPMC.Core.CompanyLocationId.DS"].CreateValues();

        let ucLocId = me.GetUserCompanyLocation({
            userName: username /* USERNAME */
        });

        let arrTemp = ucLocId.split(".");
        try {
            let defaultCompany = me.GetConfigurationTableRow({
                tableName: "DefautCompanyUser" /* STRING */,
                key: ucLocId /* STRING */
            });

            tempData.ucId = defaultCompany.ucId;
            tempData.locId = defaultCompany.locId;
            tempData.countryId = defaultCompany.countryId;
            tempData.region = defaultCompany.region;
            tempData.subRegion = defaultCompany.subRegion;
            tempData.machineType = defaultCompany.machineType;
        } catch (err) {
            try {
                let company = Things["HPMC.Core.Company.DT"].QueryDataTableEntries({
                    query: {
                        filters: {
                            type: "LIKE",
                            fieldName: "company_id",
                            value: arrTemp[2]
                        }
                    } /* QUERY */
                });
                if (arrTemp[0] === "undefined") {
                    tempData.subRegion = "";
                    tempData.region = arrTemp[1] || "";
                } else {
                    tempData.subRegion = arrTemp[1];
                    tempData.region = arrTemp[0] || "";
                }
                tempData.ucId = arrTemp.length > 2 ? arrTemp[2] : "";
                tempData.locId = arrTemp.length > 3 ? arrTemp[3] : "";
                tempData.countryId = company.country_id;
                tempData.machineType = "Sawing";
            } catch (err2) {}
        }
        result = tempData;
    } catch (error) {
        logger.error(loggerBeginning + " cannot Default value of country,company,location and machine type of the user - [ERROR]: " + error);
    }
})();


