/*
 * @name SetUserSessionSettings
 * @date 24.03.2021
 * @author Steffen Moebius
 * @param userName username of user
 * @return nothing
 *
 * [COMPLETED] [24.03.2021] 	set user specific session variables containing the countryId, ucId and locId
 */

let loggerBeginning = "[HPM.User.Helper:SetUserSessionSettings]: ";

let user = userName;

if (user === undefined || user === null) {
    user = Resources["CurrentSessionInfo"].GetCurrentUser();
}
// result: INFOTABLE dataShape: ""
let sessionValues = Resources["CurrentSessionInfo"].GetGlobalSessionValues();

let countryId = sessionValues.countryId;
let ucId = sessionValues.ucId;
let locId = sessionValues.locId;

let countryUcIdLocId = me.GetUserDefaultInformation({
    username: user /* USERNAME */
});

if (!countryId) {
    Resources["CurrentSessionInfo"].SetGlobalSessionStringValue({
        name: "countryId" /* STRING */,
        value: countryUcIdLocId.countryId /* STRING */
    });
}

if (!ucId) {
    Resources["CurrentSessionInfo"].SetGlobalSessionStringValue({
        name: "ucId" /* STRING */,
        value: countryUcIdLocId.ucId /* STRING */
    });
}

if (!locId) {
    Resources["CurrentSessionInfo"].SetGlobalSessionStringValue({
        name: "locId" /* STRING */,
        value: countryUcIdLocId.locId /* STRING */
    });
}
let result = Resources["CurrentSessionInfo"].GetGlobalSessionValues();


/*
 * @name UpdateCompanyLogoConfig
 * @date 20.01.2021
 * @author Isro Syaeful Iman
 * @param userName	username of user
 * @return infotable (HPMC.Core.CompanyLogo.DS)
 *
 * [COMPLETED] [06/01/2020] 	Update Company Logo Config Table from all location thing
 */
var result;
var loggerBeginning = "[" + me.name + ":UpdateCompanyLogoConfig]";
(function () {
    "use strict";
    try {
        var tempData = Resources["InfoTableFunctions"].CreateInfoTableFromDataShape({
            infoTableName: "InfoTable",
            dataShapeName: "HPMC.Core.CompanyLogo.DS"
        });

        var locations = ThingTemplates["HPMC.Core.Location.TT"].QueryImplementingThingsWithData();
        var newEntry = new Object();
        locations.rows.toArray().forEach((data) => {
            tempData.AddRow({
                companyLocationId: data.ucId + "." + data.locId,
                organization: data.companyName,
                description: data.address,
                companyLogo: data.brandLogo
            });
        });

        me.SetConfigurationTableRows({
            values: tempData,
            persistent: true,
            tableName: "CompanyUserLogoConfig"
        });
        var configData = me.GetConfigurationTable({
            tableName: "CompanyUserLogoConfig" /* STRING */
        });
        result = configData;
    } catch (error) {
        logger.error(loggerBeginning + " " + error);
    }
})();
